+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track = {min: number; fr: number; auto: boolean};
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		if (token === 'auto') return {min: 0, fr: 0, auto: true};
+		if (token.endsWith('fr')) return {min: 0, fr: Number.parseFloat(token) || 1, auto: false};
+		const minmax = /^minmax\\(\\s*([\\d.]+)\\s*,\\s*([\\d.]+fr|[\\d.]+)\\s*\\)$/.exec(token);
+		if (minmax) return {min: Number(minmax[1]), fr: minmax[2].endsWith('fr') ? Number.parseFloat(minmax[2]) || 1 : 0, auto: false};
+		return {min: Number.parseFloat(token) || 0, fr: 0, auto: false};
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') return [value, value + 1];
+	if (!value) return undefined;
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	return match ? [Number(match[1]), Number(match[2])] : undefined;
+};
+
+const isElement = (node: DOMNode): node is DOMElement => node.yogaNode !== undefined;
+
+const gapFor = (node: DOMElement, axis: 'column' | 'row'): number =>
+	axis === 'column' ? (node.style.columnGap ?? node.style.gap ?? 0) : (node.style.rowGap ?? node.style.gap ?? 0);
+
+const sizeTracks = (tracks: Track[], available: number, gap: number, autos: number[]): number[] => {
+	const sizes = tracks.map((track, index) => track.auto ? Math.max(track.min, autos[index] ?? 0) : track.min);
+	const remaining = Math.max(0, available - sizes.reduce((sum, size) => sum + size, 0) - Math.max(0, tracks.length - 1) * gap);
+	const totalFr = tracks.reduce((sum, track) => sum + track.fr, 0);
+	return sizes.map((size, index) => totalFr > 0 ? size + remaining * tracks[index].fr / totalFr : size);
+};
+
+const positions = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const position = offset;
+		offset += size + gap;
+		return position;
+	});
+};
+
+const spanSize = (sizes: number[], start: number, end: number, gap: number): number =>
+	sizes.slice(start, end).reduce((sum, size) => sum + size, 0) + Math.max(0, end - start - 1) * gap;
+
+const placeChildren = (children: DOMElement[], columnCount: number): Placement[] => {
+	const used = new Set<string>();
+	const placements: Placement[] = [];
+	const fits = (column: number, columnEnd: number, row: number, rowEnd: number) => {
+		if (column < 0 || columnEnd > columnCount || row < 0) return false;
+		for (let y = row; y < rowEnd; y++) for (let x = column; x < columnEnd; x++) if (used.has(`${x}:${y}`)) return false;
+		return true;
+	};
+	for (const child of children) {
+		const columns = parsePlacement(child.style.gridColumn);
+		const rows = parsePlacement(child.style.gridRow);
+		const columnSpan = columns ? columns[1] - columns[0] : 1;
+		const rowSpan = rows ? rows[1] - rows[0] : 1;
+		let column = columns ? columns[0] - 1 : 0;
+		let row = rows ? rows[0] - 1 : 0;
+		if (!columns || !rows) {
+			for (let y = rows ? row : 0; ; y++) {
+				let found = false;
+				for (let x = columns ? column : 0; x <= columnCount - columnSpan; x++) {
+					if (fits(x, x + columnSpan, y, y + rowSpan)) { column = x; row = y; found = true; break; }
+				}
+				if (found) break;
+			}
+		}
+		const placement = {column, columnEnd: column + columnSpan, row, rowEnd: row + rowSpan};
+		placements.push(placement);
+		for (let y = row; y < placement.rowEnd; y++) for (let x = column; x < placement.columnEnd; x++) used.add(`${x}:${y}`);
+	}
+	return placements;
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode!;
+	const children = node.childNodes.filter(isElement);
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) return;
+	const placements = placeChildren(children, columns.length);
+	const rows = parseTracks(node.style.gridTemplateRows);
+	const rowCount = Math.max(rows.length, ...placements.map(placement => placement.rowEnd), 0);
+	while (rows.length < rowCount) rows.push({min: 0, fr: 0, auto: true});
+	const columnGap = gapFor(node, 'column');
+	const rowGap = gapFor(node, 'row');
+	const horizontalInset = yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) + yogaNode.getComputedBorder(Yoga.EDGE_LEFT) + yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const verticalInset = yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const columnAutos = columns.map(() => 0);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		if (placement.columnEnd - placement.column === 1) columnAutos[placement.column] = Math.max(columnAutos[placement.column], child.yogaNode!.getComputedWidth());
+	}
+	const columnSizes = sizeTracks(columns, Math.max(0, yogaNode.getComputedWidth() - horizontalInset), columnGap, columnAutos);
+	const columnPositions = positions(columnSizes, columnGap);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnPositions[placement.column]);
+		child.yogaNode!.setWidth(spanSize(columnSizes, placement.column, placement.columnEnd, columnGap));
+	}
+	const rowAutos = rows.map(() => 0);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		if (placement.rowEnd - placement.row === 1) rowAutos[placement.row] = Math.max(rowAutos[placement.row], child.yogaNode!.getComputedHeight());
+	}
+	const contentHeight = Math.max(0, yogaNode.getComputedHeight() - verticalInset);
+	const rowSizes = sizeTracks(rows, contentHeight, rowGap, rowAutos);
+	const rowPositions = positions(rowSizes, rowGap);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, rowPositions[placement.row]);
+		child.yogaNode!.setHeight(spanSize(rowSizes, placement.row, placement.rowEnd, rowGap));
+	}
+	if (node.style.height === undefined) yogaNode.setHeight(rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rows.length - 1) * rowGap + verticalInset);
+};
+
+export const prepareGridLayout = (node: DOMElement): void => {
+	for (const child of node.childNodes) if (isElement(child)) prepareGridLayout(child);
+	if (node.style.display === 'grid') {
+		if (node.style.height === undefined) node.yogaNode!.setHeightAuto();
+		for (const child of node.childNodes) if (isElement(child)) child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
+	}
+};
+
+export const applyGridLayout = (node: DOMElement): void => {
+	if (node.style.display === 'grid') layoutGrid(node);
+	for (const child of node.childNodes) if (isElement(child)) applyGridLayout(child);
+};
