import Yoga from 'yoga-layout';
import {type DOMElement, type DOMNode} from './dom.js';

type Track = {min: number; fr: number; auto: boolean};
type Placement = {
	column: number;
	columnEnd: number;
	row: number;
	rowEnd: number;
};

const parseTracks = (template: string | undefined): Track[] => {
	if (!template) return [];
	const tokens = template.match(/minmax\([^)]*\)|\S+/g) ?? [];
	return tokens.map(token => {
		if (token === 'auto') return {min: 0, fr: 0, auto: true};
		if (token.endsWith('fr'))
			return {min: 0, fr: Number.parseFloat(token) || 1, auto: false};
		const minmax = /^minmax\(\s*([\d.]+)\s*,\s*([\d.]+fr|[\d.]+)\s*\)$/.exec(
			token,
		);
		if (minmax) {
			const min = minmax[1]!;
			const max = minmax[2]!;
			return {
				min: Number(min),
				fr: max.endsWith('fr') ? Number.parseFloat(max) || 1 : 0,
				auto: false,
			};
		}
		return {min: Number.parseFloat(token) || 0, fr: 0, auto: false};
	});
};

const parsePlacement = (
	value: number | string | undefined,
): [number, number] | undefined => {
	if (typeof value === 'number') return [value, value + 1];
	if (!value) return undefined;
	const match = /^\s*(\d+)\s*\/\s*(\d+)\s*$/.exec(value);
	return match ? [Number(match[1]), Number(match[2])] : undefined;
};

const isElement = (node: DOMNode): node is DOMElement =>
	node.yogaNode !== undefined;

const gapFor = (node: DOMElement, axis: 'column' | 'row'): number =>
	axis === 'column'
		? (node.style.columnGap ?? node.style.gap ?? 0)
		: (node.style.rowGap ?? node.style.gap ?? 0);

const sizeTracks = (
	tracks: Track[],
	available: number,
	gap: number,
	autos: number[],
): number[] => {
	const sizes = tracks.map((track, index) =>
		track.auto ? Math.max(track.min, autos[index] ?? 0) : track.min,
	);
	const remaining = Math.max(
		0,
		available -
			sizes.reduce((sum, size) => sum + size, 0) -
			Math.max(0, tracks.length - 1) * gap,
	);
	const totalFr = tracks.reduce((sum, track) => sum + track.fr, 0);
	return sizes.map((size, index) =>
		totalFr > 0 ? size + (remaining * tracks[index]!.fr) / totalFr : size,
	);
